content:
{
  "sentences": [
    {
      "text": "我想改期到明天下午三點。",
      "pinyin": "Wǒ xiǎng gǎiqí dào míngtiān xiàwǔ sān diǎn.",
      "pinyin_numeric": "wo3 xiang3 gai3qi2 dao4 ming2tian1 xia4wu3 san1 dian3.",
      "translation_en": "I want to reschedule to tomorrow at 3 PM.",
      "translation_ko": "내일 오후 3시로 일정을 변경하고 싶습니다."
    },
    {
      "text": "你已經預約了嗎？",
      "pinyin": "Nǐ yǐjīng yùyuē le ma?",
      "pinyin_numeric": "ni3 yi3jing1 yu4yue1 le5 ma5?",
      "translation_en": "Have you already made an appointment?",
      "translation_ko": "이미 예약하셨나요?"
    },
    {
      "text": "他想要取消預約，因為他太忙了。",
      "pinyin": "Tā xiǎng yào qǔxiāo yùyuē, yīnwèi tā tài máng le.",
      "pinyin_numeric": "ta1 xiang3 yao4 qu3xiao1 yu4yue1, yin1wei4 ta1 tai4 mang2 le5.",
      "translation_en": "He wants to cancel the appointment because he is too busy.",
      "translation_ko": "그는 너무 바빠서 예약을 취소하고 싶어 합니다."
    },
    {
      "text": "我們可以改期到這個星期五嗎？",
      "pinyin": "Wǒmen kěyǐ gǎiqí dào zhège xīngqīwǔ ma?",
      "pinyin_numeric": "wo3men5 ke3yi3 gai3qi2 dao4 zhe4ge5 xing1qi1wu3 ma5?",
      "translation_en": "Can we reschedule to this Friday?",
      "translation_ko": "이번 금요일로 일정을 변경할 수 있을까요?"
    },
    {
      "text": "請你確認預約時間。",
      "pinyin": "Qǐng nǐ quèrèn yùyuē shíjiān.",
      "pinyin_numeric": "qing3 ni3 que4ren4 yu4yue1 shi2jian1.",
      "translation_en": "Please confirm the appointment time.",
      "translation_ko": "예약 시간을 확인해 주세요."
    },
    {
      "text": "她打算提早到醫院掛號。",
      "pinyin": "Tā dǎsuàn tízǎo dào yīyuàn guàhào.",
      "pinyin_numeric": "ta1 da3suan4 ti2zao3 dao4 yi1yuan4 gua4hao4.",
      "translation_en": "She plans to arrive early at the hospital to register.",
      "translation_ko": "그녀는 병원에 일찍 도착해서 접수할 계획입니다."
    },
    {
      "text": "你為什麼想改期？",
      "pinyin": "Nǐ wèishénme xiǎng gǎiqí?",
      "pinyin_numeric": "ni3 wei4shen2me5 xiang3 gai3qi2?",
      "translation_en": "Why do you want to reschedule?",
      "translation_ko": "왜 일정을 변경하고 싶으세요?"
    },
    {
      "text": "我必須取消預約，因為我臨時有工作。",
      "pinyin": "Wǒ bìxū qǔxiāo yùyuē, yīnwèi wǒ línshí yǒu gōngzuò.",
      "pinyin_numeric": "wo3 bi4xu1 qu3xiao1 yu4yue1, yin1wei4 wo3 lin2shi2 you3 gong1zuo4.",
      "translation_en": "I have to cancel the appointment because I have work suddenly.",
      "translation_ko": "갑자기 일이 생겨서 예약을 취소해야 합니다."
    },
    {
      "text": "我們可以改期到下個星期二上午嗎？",
      "pinyin": "Wǒmen kěyǐ gǎiqí dào xià ge xīngqī'èr shàngwǔ ma?",
      "pinyin_numeric": "wo3men5 ke3yi3 gai3qi2 dao4 xia4 ge5 xing1qi1er4 shang4wu3 ma5?",
      "translation_en": "Can we reschedule to next Tuesday morning?",
      "translation_ko": "다음 주 화요일 오전으로 일정을 변경할 수 있을까요?"
    },
    {
      "text": "他已經約好了，所以不用改期。",
      "pinyin": "Tā yǐjīng yuē hǎo le, suǒyǐ bùyòng gǎiqí.",
      "pinyin_numeric": "ta1 yi3jing1 yue1 hao3 le5, suo3yi3 bu4yong4 gai3qi2.",
      "translation_en": "He has already made an appointment, so there's no need to reschedule.",
      "translation_ko": "그는 이미 약속을 잡았으므로 일정을 변경할 필요가 없습니다."
    }
  ]
}
